     1→/*
     2→ * ESP32 Triple Rotary Encoder Reader - with Position Memory
     3→ * ==========================================================
     4→ * Autonics 증분형 엔코더 1~3개 동시 읽기 (유연한 구성)
     5→ * + 절대값 원점 설정 및 위치 저장 기능 (NVS 사용)
     6→ * 
     7→ * 기능:
     8→ * - 쿼드러처 디코딩 (4배 해상도)
     9→ * - 실시간 각도 계산 (0~360도)
    10→ * - JSON 프로토콜로 PC 전송
    11→ * - 제로(원점) 리셋 명령 지원
    12→ * - ★ 절대값 원점 저장 (전원 꺼져도 유지)
    13→ * - ★ 위치 1~100 저장/불러오기/삭제/재정렬
    14→ * - ★ 1~3개 엔코더 유연하게 지원 (없는 엔코더는 자동 비활성화)
    15→ * 
    16→ * 명령어:
    17→ * - SAVE n: 현재 위치를 n번에 저장
    18→ * - SAVEAT n e1 e2 e3: 지정된 값을 n번에 저장 (재정렬용)
    19→ * - DELETE n: n번 위치 삭제
    20→ * - CLEAR: 모든 위치 삭제
    21→ * - GETALL: 모든 위치 조회
    22→ * - ENABLE n: n번 엔코더 활성화 (1~3)
    23→ * - DISABLE n: n번 엔코더 비활성화 (1~3)
    24→ * 
    25→ * 작성일: 2024
    26→ */
    27→
    28→#include <Arduino.h>
    29→#include <Preferences.h>  // ESP32 NVS (비휘발성 저장소)
    30→
    31→// ============================================================
    32→// 핀 설정 (쉽게 변경 가능하도록 상수로 분리)
    33→// ============================================================
    34→#define ENC1_PIN_A    34    // Encoder 1 - A 신호
    35→#define ENC1_PIN_B    35    // Encoder 1 - B 신호
    36→#define ENC1_PIN_Z    32    // Encoder 1 - Z 신호 (옵션)
    37→
    38→#define ENC2_PIN_A    36    // Encoder 2 - A 신호
    39→#define ENC2_PIN_B    39    // Encoder 2 - B 신호
    40→#define ENC2_PIN_Z    33    // Encoder 2 - Z 신호 (옵션)
    41→
    42→#define ENC3_PIN_A    25    // Encoder 3 - A 신호
    43→#define ENC3_PIN_B    26    // Encoder 3 - B 신호
    44→#define ENC3_PIN_Z    27    // Encoder 3 - Z 신호 (옵션)
    45→
    46→// ============================================================
    47→// 엔코더 설정
    48→// ============================================================
    49→#define ENCODER_PPR         100     // 엔코더 PPR (Pulses Per Revolution)
    50→#define QUADRATURE_MULT     4       // 쿼드러처 4배
    51→#define COUNTS_PER_REV      (ENCODER_PPR * QUADRATURE_MULT)  // 총 카운트/회전
    52→#define MAX_ENCODERS        3       // 최대 엔코더 수
    53→
    54→// ============================================================
    55→// 통신 설정
    56→// ============================================================
    57→#define SERIAL_BAUD         921600  // 고속 통신
    58→#define UPDATE_INTERVAL_MS  10      // 업데이트 주기 (10ms = 100Hz)
    59→
    60→// ============================================================
    61→// 위치 저장 설정
    62→// ============================================================
    63→#define MAX_POSITIONS       100     // 저장 가능한 위치 개수
    64→
    65→// ============================================================
    66→// 공차 설정
    67→// ============================================================
    68→int position_tolerance = 5;         // 위치 허용 오차 (카운트, 변경 가능)
    69→
    70→// ============================================================
    71→// 글로벌 변수 (volatile: 인터럽트에서 사용)
    72→// ============================================================
    73→volatile int32_t enc1_count = 0;
    74→volatile int32_t enc2_count = 0;
    75→volatile int32_t enc3_count = 0;
    76→
    77→// 마지막 상태 저장 (쿼드러처 디코딩용)
    78→volatile uint8_t enc1_last_state = 0;
    79→volatile uint8_t enc2_last_state = 0;
    80→volatile uint8_t enc3_last_state = 0;
    81→
    82→// 절대값 오프셋 (원점 보정용)
    83→int32_t enc1_offset = 0;
    84→int32_t enc2_offset = 0;
    85→int32_t enc3_offset = 0;
    86→
    87→// 엔코더 활성화 상태 (true = 사용, false = 미사용)
    88→bool enc1_enabled = true;
    89→bool enc2_enabled = true;
    90→bool enc3_enabled = true;
    91→
    92→// 저장된 위치들 [위치번호][enc1, enc2, enc3]
    93→int32_t saved_positions[MAX_POSITIONS][MAX_ENCODERS];
    94→
    95→// 타이밍
    96→unsigned long last_update_time = 0;
    97→unsigned long start_time = 0;
    98→
    99→// 시리얼 수신 버퍼
   100→String serial_buffer = "";
   101→
   102→// NVS 저장소
   103→Preferences preferences;
   104→
   105→// ============================================================
   106→// 쿼드러처 디코딩 테이블
   107→// ============================================================
   108→const int8_t QUAD_TABLE[4][4] = {
   109→  {   0,  +1,  -1,   0 },
   110→  {  -1,   0,   0,  +1 },
   111→  {  +1,   0,   0,  -1 },
   112→  {   0,  -1,  +1,   0 }
   113→};
   114→
   115→// ============================================================
   116→// 인터럽트 핸들러 - Encoder 1
   117→// ============================================================
   118→void IRAM_ATTR enc1_isr() {
   119→  uint8_t a = digitalRead(ENC1_PIN_A);
   120→  uint8_t b = digitalRead(ENC1_PIN_B);
   121→  uint8_t current_state = (b << 1) | a;
   122→  
   123→  enc1_count += QUAD_TABLE[enc1_last_state][current_state];
   124→  enc1_last_state = current_state;
   125→}
   126→
   127→// ============================================================
   128→// 인터럽트 핸들러 - Encoder 2
   129→// ============================================================
   130→void IRAM_ATTR enc2_isr() {
   131→  uint8_t a = digitalRead(ENC2_PIN_A);
   132→  uint8_t b = digitalRead(ENC2_PIN_B);
   133→  uint8_t current_state = (b << 1) | a;
   134→  
   135→  enc2_count += QUAD_TABLE[enc2_last_state][current_state];
   136→  enc2_last_state = current_state;
   137→}
   138→
   139→// ============================================================
   140→// 인터럽트 핸들러 - Encoder 3
   141→// ============================================================
   142→void IRAM_ATTR enc3_isr() {
   143→  uint8_t a = digitalRead(ENC3_PIN_A);
   144→  uint8_t b = digitalRead(ENC3_PIN_B);
   145→  uint8_t current_state = (b << 1) | a;
   146→  
   147→  enc3_count += QUAD_TABLE[enc3_last_state][current_state];
   148→  enc3_last_state = current_state;
   149→}
   150→
   151→// ============================================================
   152→// 절대 카운트 (오프셋 적용)
   153→// ============================================================
   154→int32_t getAbsoluteCount1() {
   155→  return enc1_count - enc1_offset;
   156→}
   157→
   158→int32_t getAbsoluteCount2() {
   159→  return enc2_count - enc2_offset;
   160→}
   161→
   162→int32_t getAbsoluteCount3() {
   163→  return enc3_count - enc3_offset;
   164→}
   165→
   166→// ============================================================
   167→// 카운트 -> 각도 변환 (0~360도)
   168→// ============================================================
   169→float countToDegree(int32_t count) {
   170→  int32_t count_mod = ((count % COUNTS_PER_REV) + COUNTS_PER_REV) % COUNTS_PER_REV;
   171→  return (float)count_mod / COUNTS_PER_REV * 360.0f;
   172→}
   173→
   174→// ============================================================
   175→// NVS에 오프셋 저장
   176→// ============================================================
   177→void saveOffsets() {
   178→  preferences.begin("encoder", false);
   179→  preferences.putInt("e1_offset", enc1_offset);
   180→  preferences.putInt("e2_offset", enc2_offset);
   181→  preferences.putInt("e3_offset", enc3_offset);
   182→  preferences.end();
   183→}
   184→
   185→// ============================================================
   186→// NVS에서 오프셋 불러오기
   187→// ============================================================
   188→void loadOffsets() {
   189→  preferences.begin("encoder", true);
   190→  enc1_offset = preferences.getInt("e1_offset", 0);
   191→  enc2_offset = preferences.getInt("e2_offset", 0);
   192→  enc3_offset = preferences.getInt("e3_offset", 0);
   193→  preferences.end();
   194→}
   195→
   196→// ============================================================
   197→// NVS에 활성화 상태 저장
   198→// ============================================================
   199→void saveEnabledState() {
   200→  preferences.begin("encoder", false);
   201→  preferences.putBool("e1_en", enc1_enabled);
   202→  preferences.putBool("e2_en", enc2_enabled);
   203→  preferences.putBool("e3_en", enc3_enabled);
   204→  preferences.end();
   205→}
   206→
   207→// ============================================================
   208→// NVS에서 활성화 상태 불러오기
   209→// ============================================================
   210→void loadEnabledState() {
   211→  preferences.begin("encoder", true);
   212→  enc1_enabled = preferences.getBool("e1_en", true);
   213→  enc2_enabled = preferences.getBool("e2_en", true);
   214→  enc3_enabled = preferences.getBool("e3_en", true);
   215→  preferences.end();
   216→}
   217→
   218→// ============================================================
   219→// 위치 저장
   220→// ============================================================
   221→void savePosition(int pos) {
   222→  if (pos < 1 || pos > MAX_POSITIONS) return;
   223→  
   224→  int idx = pos - 1;
   225→  saved_positions[idx][0] = getAbsoluteCount1();
   226→  saved_positions[idx][1] = getAbsoluteCount2();
   227→  saved_positions[idx][2] = getAbsoluteCount3();
   228→  
   229→  preferences.begin("encoder", false);
   230→  String key1 = "pos" + String(pos) + "_e1";
   231→  String key2 = "pos" + String(pos) + "_e2";
   232→  String key3 = "pos" + String(pos) + "_e3";
   233→  preferences.putInt(key1.c_str(), saved_positions[idx][0]);
   234→  preferences.putInt(key2.c_str(), saved_positions[idx][1]);
   235→  preferences.putInt(key3.c_str(), saved_positions[idx][2]);
   236→  preferences.end();
   237→  
   238→  Serial.print("{\"cmd\":\"SAVE\",\"pos\":");
   239→  Serial.print(pos);
   240→  if (enc1_enabled) {
   241→    Serial.print(",\"e1\":");
   242→    Serial.print(saved_positions[idx][0]);
   243→  }
   244→  if (enc2_enabled) {
   245→    Serial.print(",\"e2\":");
   246→    Serial.print(saved_positions[idx][1]);
   247→  }
   248→  if (enc3_enabled) {
   249→    Serial.print(",\"e3\":");
   250→    Serial.print(saved_positions[idx][2]);
   251→  }
   252→  Serial.println(",\"ok\":true}");
   253→}
   254→
   255→// ============================================================
   256→// 저장된 위치 불러오기
   257→// ============================================================
   258→void loadPositions() {
   259→  preferences.begin("encoder", true);
   260→  for (int i = 0; i < MAX_POSITIONS; i++) {
   261→    String key1 = "pos" + String(i+1) + "_e1";
   262→    String key2 = "pos" + String(i+1) + "_e2";
   263→    String key3 = "pos" + String(i+1) + "_e3";
   264→    saved_positions[i][0] = preferences.getInt(key1.c_str(), 0);
   265→    saved_positions[i][1] = preferences.getInt(key2.c_str(), 0);
   266→    saved_positions[i][2] = preferences.getInt(key3.c_str(), 0);
   267→  }
   268→  preferences.end();
   269→}
   270→
   271→// ============================================================
   272→// 저장된 위치 정보 전송
   273→// ============================================================
   274→void sendPositionInfo(int pos) {
   275→  if (pos < 1 || pos > MAX_POSITIONS) return;
   276→  
   277→  int idx = pos - 1;
   278→  
   279→  Serial.print("{\"cmd\":\"POS\",\"pos\":");
   280→  Serial.print(pos);
   281→  
   282→  if (enc1_enabled) {
   283→    float deg1 = countToDegree(saved_positions[idx][0]);
   284→    Serial.print(",\"e1\":{\"cnt\":");
   285→    Serial.print(saved_positions[idx][0]);
   286→    Serial.print(",\"deg\":");
   287→    Serial.print(deg1, 1);
   288→    Serial.print("}");
   289→  }
   290→  
   291→  if (enc2_enabled) {
   292→    float deg2 = countToDegree(saved_positions[idx][1]);
   293→    Serial.print(",\"e2\":{\"cnt\":");
   294→    Serial.print(saved_positions[idx][1]);
   295→    Serial.print(",\"deg\":");
   296→    Serial.print(deg2, 1);
   297→    Serial.print("}");
   298→  }
   299→  
   300→  if (enc3_enabled) {
   301→    float deg3 = countToDegree(saved_positions[idx][2]);
   302→    Serial.print(",\"e3\":{\"cnt\":");
   303→    Serial.print(saved_positions[idx][2]);
   304→    Serial.print(",\"deg\":");
   305→    Serial.print(deg3, 1);
   306→    Serial.print("}");
   307→  }
   308→  
   309→  Serial.println(",\"ok\":true}");
   310→}
   311→
   312→// ============================================================
   313→// 모든 저장된 위치 정보 전송
   314→// ============================================================
   315→void sendAllPositions() {
   316→  Serial.print("{\"cmd\":\"POSITIONS\",\"data\":[");
   317→  for (int i = 0; i < MAX_POSITIONS; i++) {
   318→    if (i > 0) Serial.print(",");
   319→    Serial.print("{\"pos\":");
   320→    Serial.print(i + 1);
   321→    if (enc1_enabled) {
   322→      Serial.print(",\"e1\":");
   323→      Serial.print(saved_positions[i][0]);
   324→    }
   325→    if (enc2_enabled) {
   326→      Serial.print(",\"e2\":");
   327→      Serial.print(saved_positions[i][1]);
   328→    }
   329→    if (enc3_enabled) {
   330→      Serial.print(",\"e3\":");
   331→      Serial.print(saved_positions[i][2]);
   332→    }
   333→    Serial.print("}");
   334→  }
   335→  Serial.println("],\"ok\":true}");
   336→}
   337→
   338→// ============================================================
   339→// 활성화된 엔코더 수 반환
   340→// ============================================================
   341→int getActiveEncoderCount() {
   342→  int count = 0;
   343→  if (enc1_enabled) count++;
   344→  if (enc2_enabled) count++;
   345→  if (enc3_enabled) count++;
   346→  return count;
   347→}
   348→
   349→// ============================================================
   350→// 시리얼 명령 처리
   351→// ============================================================
   352→void processCommand(String cmd) {
   353→  cmd.trim();
   354→  cmd.toUpperCase();
   355→  
   356→  // ZERO 명령들
   357→  if (cmd == "ZERO 1" || cmd == "ZERO1") {
   358→    enc1_count = 0;
   359→    Serial.println("{\"cmd\":\"ZERO\",\"enc\":1,\"ok\":true}");
   360→  }
   361→  else if (cmd == "ZERO 2" || cmd == "ZERO2") {
   362→    enc2_count = 0;
   363→    Serial.println("{\"cmd\":\"ZERO\",\"enc\":2,\"ok\":true}");
   364→  }
   365→  else if (cmd == "ZERO 3" || cmd == "ZERO3") {
   366→    enc3_count = 0;
   367→    Serial.println("{\"cmd\":\"ZERO\",\"enc\":3,\"ok\":true}");
   368→  }
   369→  else if (cmd == "ZERO ALL" || cmd == "ZEROALL" || cmd == "ZERO") {
   370→    enc1_count = 0;
   371→    enc2_count = 0;
   372→    enc3_count = 0;
   373→    Serial.println("{\"cmd\":\"ZERO\",\"enc\":\"all\",\"ok\":true}");
   374→  }
   375→  
   376→  // ★ 엔코더 활성화/비활성화
   377→  else if (cmd.startsWith("ENABLE ")) {
   378→    int enc = cmd.substring(7).toInt();
   379→    if (enc == 1) { enc1_enabled = true; saveEnabledState(); Serial.println("{\"cmd\":\"ENABLE\",\"enc\":1,\"ok\":true}"); }
   380→    else if (enc == 2) { enc2_enabled = true; saveEnabledState(); Serial.println("{\"cmd\":\"ENABLE\",\"enc\":2,\"ok\":true}"); }
   381→    else if (enc == 3) { enc3_enabled = true; saveEnabledState(); Serial.println("{\"cmd\":\"ENABLE\",\"enc\":3,\"ok\":true}"); }
   382→    else { Serial.println("{\"cmd\":\"ENABLE\",\"ok\":false,\"error\":\"Invalid encoder (1-3)\"}"); }
   383→  }
   384→  else if (cmd.startsWith("DISABLE ")) {
   385→    int enc = cmd.substring(8).toInt();
   386→    if (enc == 1) { enc1_enabled = false; saveEnabledState(); Serial.println("{\"cmd\":\"DISABLE\",\"enc\":1,\"ok\":true}"); }
   387→    else if (enc == 2) { enc2_enabled = false; saveEnabledState(); Serial.println("{\"cmd\":\"DISABLE\",\"enc\":2,\"ok\":true}"); }
   388→    else if (enc == 3) { enc3_enabled = false; saveEnabledState(); Serial.println("{\"cmd\":\"DISABLE\",\"enc\":3,\"ok\":true}"); }
   389→    else { Serial.println("{\"cmd\":\"DISABLE\",\"ok\":false,\"error\":\"Invalid encoder (1-3)\"}"); }
   390→  }
   391→  
   392→  // ★ 절대값 원점 설정 (현재 위치를 0으로, NVS에 저장)
   393→  else if (cmd == "SETHOME" || cmd == "SET HOME" || cmd == "ABSOLUTE") {
   394→    enc1_offset = enc1_count;
   395→    enc2_offset = enc2_count;
   396→    enc3_offset = enc3_count;
   397→    saveOffsets();
   398→    Serial.print("{\"cmd\":\"SETHOME\"");
   399→    if (enc1_enabled) { Serial.print(",\"e1_offset\":"); Serial.print(enc1_offset); }
   400→    if (enc2_enabled) { Serial.print(",\"e2_offset\":"); Serial.print(enc2_offset); }
   401→    if (enc3_enabled) { Serial.print(",\"e3_offset\":"); Serial.print(enc3_offset); }
   402→    Serial.println(",\"ok\":true}");
   403→  }
   404→  
   405→  // ★ 개별 엔코더 원점 설정
   406→  else if (cmd == "SETHOME 1" || cmd == "SETHOME1") {
   407→    enc1_offset = enc1_count;
   408→    saveOffsets();
   409→    Serial.print("{\"cmd\":\"SETHOME\",\"enc\":1,\"offset\":");
   410→    Serial.print(enc1_offset);
   411→    Serial.println(",\"ok\":true}");
   412→  }
   413→  else if (cmd == "SETHOME 2" || cmd == "SETHOME2") {
   414→    enc2_offset = enc2_count;
   415→    saveOffsets();
   416→    Serial.print("{\"cmd\":\"SETHOME\",\"enc\":2,\"offset\":");
   417→    Serial.print(enc2_offset);
   418→    Serial.println(",\"ok\":true}");
   419→  }
   420→  else if (cmd == "SETHOME 3" || cmd == "SETHOME3") {
   421→    enc3_offset = enc3_count;
   422→    saveOffsets();
   423→    Serial.print("{\"cmd\":\"SETHOME\",\"enc\":3,\"offset\":");
   424→    Serial.print(enc3_offset);
   425→    Serial.println(",\"ok\":true}");
   426→  }
   427→  
   428→  // ★ 위치 저장 (SAVE 1 ~ SAVE 100)
   429→  else if (cmd.startsWith("SAVE ")) {
   430→    int pos = cmd.substring(5).toInt();
   431→    savePosition(pos);
   432→  }
   433→  else if (cmd.startsWith("SAVE")) {
   434→    int pos = cmd.substring(4).toInt();
   435→    if (pos > 0) savePosition(pos);
   436→  }
   437→  
   438→  // ★ 지정된 값으로 위치 저장 (SAVEAT pos e1 e2 e3) - 재정렬용
   439→  else if (cmd.startsWith("SAVEAT ")) {
   440→    // "SAVEAT 1 100 200 300" 형태
   441→    String params = cmd.substring(7);
   442→    int space1 = params.indexOf(' ');
   443→    int space2 = params.indexOf(' ', space1 + 1);
   444→    int space3 = params.indexOf(' ', space2 + 1);
   445→    
   446→    if (space1 > 0 && space2 > space1) {
   447→      int pos = params.substring(0, space1).toInt();
   448→      int32_t e1 = params.substring(space1 + 1, space2).toInt();
   449→      int32_t e2 = 0;
   450→      int32_t e3 = 0;
   451→      
   452→      if (space3 > space2) {
   453→        e2 = params.substring(space2 + 1, space3).toInt();
   454→        e3 = params.substring(space3 + 1).toInt();
   455→      } else {
   456→        e2 = params.substring(space2 + 1).toInt();
   457→      }
   458→      
   459→      if (pos >= 1 && pos <= MAX_POSITIONS) {
   460→        int idx = pos - 1;
   461→        saved_positions[idx][0] = e1;
   462→        saved_positions[idx][1] = e2;
   463→        saved_positions[idx][2] = e3;
   464→        
   465→        preferences.begin("encoder", false);
   466→        String key1 = "pos" + String(pos) + "_e1";
   467→        String key2 = "pos" + String(pos) + "_e2";
   468→        String key3 = "pos" + String(pos) + "_e3";
   469→        preferences.putInt(key1.c_str(), e1);
   470→        preferences.putInt(key2.c_str(), e2);
   471→        preferences.putInt(key3.c_str(), e3);
   472→        preferences.end();
   473→        
   474→        Serial.print("{\"cmd\":\"SAVEAT\",\"pos\":");
   475→        Serial.print(pos);
   476→        Serial.print(",\"e1\":");
   477→        Serial.print(e1);
   478→        Serial.print(",\"e2\":");
   479→        Serial.print(e2);
   480→        Serial.print(",\"e3\":");
   481→        Serial.print(e3);
   482→        Serial.println(",\"ok\":true}");
   483→      }
   484→    }
   485→  }
   486→  
   487→  // ★ 저장된 위치 조회
   488→  else if (cmd.startsWith("GET ")) {
   489→    int pos = cmd.substring(4).toInt();
   490→    sendPositionInfo(pos);
   491→  }
   492→  else if (cmd == "GETALL" || cmd == "GET ALL" || cmd == "POSITIONS") {
   493→    sendAllPositions();
   494→  }
   495→  
   496→  // ★ 위치 삭제 (DELETE 1 ~ DELETE 100)
   497→  else if (cmd.startsWith("DELETE ")) {
   498→    int pos = cmd.substring(7).toInt();
   499→    if (pos >= 1 && pos <= MAX_POSITIONS) {
   500→      int idx = pos - 1;
   501→      saved_positions[idx][0] = 0;
   502→      saved_positions[idx][1] = 0;
   503→      saved_positions[idx][2] = 0;
   504→      
   505→      preferences.begin("encoder", false);
   506→      String key1 = "pos" + String(pos) + "_e1";
   507→      String key2 = "pos" + String(pos) + "_e2";
   508→      String key3 = "pos" + String(pos) + "_e3";
   509→      preferences.putInt(key1.c_str(), 0);
   510→      preferences.putInt(key2.c_str(), 0);
   511→      preferences.putInt(key3.c_str(), 0);
   512→      preferences.end();
   513→      
   514→      Serial.print("{\"cmd\":\"DELETE\",\"pos\":");
   515→      Serial.print(pos);
   516→      Serial.println(",\"ok\":true}");
   517→    } else {
   518→      Serial.println("{\"cmd\":\"DELETE\",\"ok\":false,\"error\":\"Invalid position\"}");
   519→    }
   520→  }
   521→  
   522→  // ★ 모든 위치 삭제 (CLEAR)
   523→  else if (cmd == "CLEAR" || cmd == "CLEARALL") {
   524→    preferences.begin("encoder", false);
   525→    for (int i = 0; i < MAX_POSITIONS; i++) {
   526→      saved_positions[i][0] = 0;
   527→      saved_positions[i][1] = 0;
   528→      saved_positions[i][2] = 0;
   529→      String key1 = "pos" + String(i+1) + "_e1";
   530→      String key2 = "pos" + String(i+1) + "_e2";
   531→      String key3 = "pos" + String(i+1) + "_e3";
   532→      preferences.putInt(key1.c_str(), 0);
   533→      preferences.putInt(key2.c_str(), 0);
   534→      preferences.putInt(key3.c_str(), 0);
   535→    }
   536→    preferences.end();
   537→    Serial.println("{\"cmd\":\"CLEAR\",\"ok\":true}");
   538→  }
   539→  
   540→  // 상태 조회
   541→  else if (cmd == "STATUS" || cmd == "?") {
   542→    sendEncoderData();
   543→  }
   544→  
   545→  // 시스템 정보
   546→  else if (cmd == "INFO") {
   547→    Serial.print("{\"ppr\":");
   548→    Serial.print(ENCODER_PPR);
   549→    Serial.print(",\"cpr\":");
   550→    Serial.print(COUNTS_PER_REV);
   551→    Serial.print(",\"hz\":");
   552→    Serial.print(1000 / UPDATE_INTERVAL_MS);
   553→    Serial.print(",\"baud\":");
   554→    Serial.print(SERIAL_BAUD);
   555→    Serial.print(",\"positions\":");
   556→    Serial.print(MAX_POSITIONS);
   557→    Serial.print(",\"max_encoders\":");
   558→    Serial.print(MAX_ENCODERS);
   559→    Serial.print(",\"active_encoders\":");
   560→    Serial.print(getActiveEncoderCount());
   561→    Serial.print(",\"e1_en\":");
   562→    Serial.print(enc1_enabled ? "true" : "false");
   563→    Serial.print(",\"e2_en\":");
   564→    Serial.print(enc2_enabled ? "true" : "false");
   565→    Serial.print(",\"e3_en\":");
   566→    Serial.print(enc3_enabled ? "true" : "false");
   567→    Serial.println(",\"ok\":true}");
   568→  }
   569→  
   570→  // ★ 공차 설정 (TOLERANCE 5 또는 TOL 5)
   571→  else if (cmd.startsWith("TOLERANCE ") || cmd.startsWith("TOL ")) {
   572→    int tol = cmd.substring(cmd.indexOf(' ') + 1).toInt();
   573→    if (tol >= 1 && tol <= 100) {
   574→      position_tolerance = tol;
   575→      float tol_deg = (float)tol / COUNTS_PER_REV * 360.0;
   576→      Serial.print("{\"cmd\":\"TOLERANCE\",\"cnt\":");
   577→      Serial.print(tol);
   578→      Serial.print(",\"deg\":");
   579→      Serial.print(tol_deg, 1);
   580→      Serial.println(",\"ok\":true}");
   581→    } else {
   582→      Serial.println("{\"cmd\":\"TOLERANCE\",\"ok\":false,\"error\":\"Invalid (1-100)\"}");
   583→    }
   584→  }
   585→  
   586→  // 알 수 없는 명령
   587→  else {
   588→    Serial.print("{\"cmd\":\"UNKNOWN\",\"input\":\"");
   589→    Serial.print(cmd);
   590→    Serial.println("\",\"ok\":false}");
   591→  }
   592→}
   593→
   594→// ============================================================
   595→// 엔코더 데이터 전송 (JSON 포맷)
   596→// ============================================================
   597→void sendEncoderData() {
   598→  noInterrupts();
   599→  int32_t cnt1 = enc1_count;
   600→  int32_t cnt2 = enc2_count;
   601→  int32_t cnt3 = enc3_count;
   602→  interrupts();
   603→  
   604→  // 절대 카운트 (오프셋 적용)
   605→  int32_t abs1 = cnt1 - enc1_offset;
   606→  int32_t abs2 = cnt2 - enc2_offset;
   607→  int32_t abs3 = cnt3 - enc3_offset;
   608→  
   609→  // 타임스탬프 (ms)
   610→  unsigned long timestamp = millis() - start_time;
   611→  
   612→  // JSON 출력
   613→  Serial.print("{\"t\":");
   614→  Serial.print(timestamp);
   615→  
   616→  if (enc1_enabled) {
   617→    float deg1 = countToDegree(abs1);
   618→    Serial.print(",\"e1\":{\"cnt\":");
   619→    Serial.print(abs1);
   620→    Serial.print(",\"deg\":");
   621→    Serial.print(deg1, 1);
   622→    Serial.print("}");
   623→  }
   624→  
   625→  if (enc2_enabled) {
   626→    float deg2 = countToDegree(abs2);
   627→    Serial.print(",\"e2\":{\"cnt\":");
   628→    Serial.print(abs2);
   629→    Serial.print(",\"deg\":");
   630→    Serial.print(deg2, 1);
   631→    Serial.print("}");
   632→  }
   633→  
   634→  if (enc3_enabled) {
   635→    float deg3 = countToDegree(abs3);
   636→    Serial.print(",\"e3\":{\"cnt\":");
   637→    Serial.print(abs3);
   638→    Serial.print(",\"deg\":");
   639→    Serial.print(deg3, 1);
   640→    Serial.print("}");
   641→  }
   642→  
   643→  Serial.println(",\"ok\":true}");
   644→}
   645→
   646→// ============================================================
   647→// 인터럽트 설정/해제 함수
   648→// ============================================================
   649→void setupEncoder1Interrupts() {
   650→  attachInterrupt(digitalPinToInterrupt(ENC1_PIN_A), enc1_isr, CHANGE);
   651→  attachInterrupt(digitalPinToInterrupt(ENC1_PIN_B), enc1_isr, CHANGE);
   652→}
   653→
   654→void setupEncoder2Interrupts() {
   655→  attachInterrupt(digitalPinToInterrupt(ENC2_PIN_A), enc2_isr, CHANGE);
   656→  attachInterrupt(digitalPinToInterrupt(ENC2_PIN_B), enc2_isr, CHANGE);
   657→}
   658→
   659→void setupEncoder3Interrupts() {
   660→  attachInterrupt(digitalPinToInterrupt(ENC3_PIN_A), enc3_isr, CHANGE);
   661→  attachInterrupt(digitalPinToInterrupt(ENC3_PIN_B), enc3_isr, CHANGE);
   662→}
   663→
   664→// ============================================================
   665→// 초기화
   666→// ============================================================
   667→void setup() {
   668→  // 시리얼 초기화
   669→  Serial.begin(SERIAL_BAUD);
   670→  while (!Serial) { delay(10); }
   671→  
   672→  // 핀 설정 - Encoder 1
   673→  pinMode(ENC1_PIN_A, INPUT);
   674→  pinMode(ENC1_PIN_B, INPUT);
   675→  pinMode(ENC1_PIN_Z, INPUT);
   676→  
   677→  // 핀 설정 - Encoder 2
   678→  pinMode(ENC2_PIN_A, INPUT);
   679→  pinMode(ENC2_PIN_B, INPUT);
   680→  pinMode(ENC2_PIN_Z, INPUT);
   681→  
   682→  // 핀 설정 - Encoder 3
   683→  pinMode(ENC3_PIN_A, INPUT);
   684→  pinMode(ENC3_PIN_B, INPUT);
   685→  pinMode(ENC3_PIN_Z, INPUT);
   686→  
   687→  // NVS에서 저장된 값 불러오기
   688→  loadOffsets();
   689→  loadPositions();
   690→  loadEnabledState();
   691→  
   692→  // 초기 상태 읽기
   693→  enc1_last_state = (digitalRead(ENC1_PIN_B) << 1) | digitalRead(ENC1_PIN_A);
   694→  enc2_last_state = (digitalRead(ENC2_PIN_B) << 1) | digitalRead(ENC2_PIN_A);
   695→  enc3_last_state = (digitalRead(ENC3_PIN_B) << 1) | digitalRead(ENC3_PIN_A);
   696→  
   697→  // 인터럽트 설정 (모든 엔코더에 대해 설정, 활성화 여부와 무관하게)
   698→  // 비활성화된 엔코더도 인터럽트는 유지하고, 출력만 제어
   699→  setupEncoder1Interrupts();
   700→  setupEncoder2Interrupts();
   701→  setupEncoder3Interrupts();
   702→  
   703→  // 시작 시간 기록
   704→  start_time = millis();
   705→  last_update_time = start_time;
   706→  
   707→  // 시작 메시지
   708→  Serial.print("{\"msg\":\"ESP32 Triple Encoder Ready\"");
   709→  Serial.print(",\"active_encoders\":");
   710→  Serial.print(getActiveEncoderCount());
   711→  if (enc1_enabled) { Serial.print(",\"e1_offset\":"); Serial.print(enc1_offset); }
   712→  if (enc2_enabled) { Serial.print(",\"e2_offset\":"); Serial.print(enc2_offset); }
   713→  if (enc3_enabled) { Serial.print(",\"e3_offset\":"); Serial.print(enc3_offset); }
   714→  Serial.print(",\"e1_en\":");
   715→  Serial.print(enc1_enabled ? "true" : "false");
   716→  Serial.print(",\"e2_en\":");
   717→  Serial.print(enc2_enabled ? "true" : "false");
   718→  Serial.print(",\"e3_en\":");
   719→  Serial.print(enc3_enabled ? "true" : "false");
   720→  Serial.println(",\"ok\":true}");
   721→  
   722→  delay(100);
   723→}
   724→
   725→// ============================================================
   726→// 메인 루프
   727→// ============================================================
   728→void loop() {
   729→  unsigned long current_time = millis();
   730→  
   731→  // 주기적 데이터 전송
   732→  if (current_time - last_update_time >= UPDATE_INTERVAL_MS) {
   733→    last_update_time = current_time;
   734→    sendEncoderData();
   735→  }
   736→  
   737→  // 시리얼 명령 수신
   738→  while (Serial.available() > 0) {
   739→    char c = Serial.read();
   740→    if (c == '\n' || c == '\r') {
   741→      if (serial_buffer.length() > 0) {
   742→        processCommand(serial_buffer);
   743→        serial_buffer = "";
   744→      }
   745→    } else {
   746→      serial_buffer += c;
   747→      if (serial_buffer.length() > 64) {
   748→        serial_buffer = "";
   749→      }
   750→    }
   751→  }
   752→}
