// 시리얼 명령 처리
// ============================================================
void processCommand(String cmd) {
  cmd.trim();
  cmd.toUpperCase();

  // ZERO: 카운트 리셋 (NVS 저장 안함)
  if (cmd == "ZERO") {
    noInterrupts();
    enc_count = 0;
    interrupts();
    enc_offset = 0;
    Serial.println("{\"cmd\":\"ZERO\",\"ok\":true}");
  }

  // SETHOME: 현재 위치를 절대 원점으로 NVS 저장
  else if (cmd == "SETHOME") {
    noInterrupts();
    enc_offset = enc_count;
    interrupts();
    saveOffset();
    Serial.print("{\"cmd\":\"SETHOME\",\"offset\":");
    Serial.print(enc_offset);
    Serial.println(",\"ok\":true}");
  }

  // SAVE n
  else if (cmd.startsWith("SAVE ") || cmd.startsWith("SAVE")) {
    int n = cmd.substring(4).trim().toInt();
    if (n >= 1 && n <= MAX_POSITIONS) {
      int idx = n - 1;
      saved_positions[idx] = getAbsCount();
      savePositionNVS(idx);
      float deg = countToDegree(saved_positions[idx]);
      Serial.print("{\"cmd\":\"SAVE\",\"pos\":");
      Serial.print(n);
      Serial.print(",\"cnt\":");
      Serial.print(saved_positions[idx]);
      Serial.print(",\"deg\":");
      Serial.print(deg, 2);
      Serial.println(",\"ok\":true}");
    } else {
      Serial.println("{\"cmd\":\"SAVE\",\"ok\":false,\"error\":\"Invalid pos (1-100)\"}");
    }
  }

  // GET n
  else if (cmd.startsWith("GET ")) {
    int n = cmd.substring(4).toInt();
    sendPositionInfo(n);
  }

  // GETALL
  else if (cmd == "GETALL") {
    sendAllPositions();
  }

  // DELETE n
  else if (cmd.startsWith("DELETE ")) {
    int n = cmd.substring(7).toInt();
    if (n >= 1 && n <= MAX_POSITIONS) {
      int idx = n - 1;
      saved_positions[idx] = INT32_MIN;
      preferences.begin("enc", false);
      String key = "p" + String(n);
      preferences.putInt(key.c_str(), INT32_MIN);
      preferences.end();
      Serial.print("{\"cmd\":\"DELETE\",\"pos\":");
      Serial.print(n);
      Serial.println(",\"ok\":true}");
    } else {
      Serial.println("{\"cmd\":\"DELETE\",\"ok\":false,\"error\":\"Invalid pos\"}");
    }
  }

  // CLEAR: 모든 위치 삭제
  else if (cmd == "CLEAR") {
    preferences.begin("enc", false);
    for (int i = 0; i < MAX_POSITIONS; i++) {
      saved_positions[i] = INT32_MIN;
      String key = "p" + String(i + 1);
      preferences.putInt(key.c_str(), INT32_MIN);
    }
    preferences.end();
    Serial.println("{\"cmd\":\"CLEAR\",\"ok\":true}");
  }

  // ZUSE / ZNUSE: Z채널 보정 on/off
  else if (cmd == "ZUSE") {
    use_z_correction = true;
    Serial.println("{\"cmd\":\"ZUSE\",\"z_correction\":true,\"ok\":true}");
  }
  else if (cmd == "ZNUSE") {
    use_z_correction = false;
    Serial.println("{\"cmd\":\"ZNUSE\",\"z_correction\":false,\"ok\":true}");
  }

  // TOL n: 허용 오차 설정
  else if (cmd.startsWith("TOL ")) {
    int tol = cmd.substring(4).toInt();
    if (tol >= 1 && tol <= 1000) {
      position_tolerance = tol;
      float tol_deg = (float)tol / COUNTS_PER_REV * 360.0f;
      Serial.print("{\"cmd\":\"TOL\",\"cnt\":");
      Serial.print(tol);
      Serial.print(",\"deg\":");
      Serial.print(tol_deg, 3);
      Serial.println(",\"ok\":true}");
    } else {
      Serial.println("{\"cmd\":\"TOL\",\"ok\":false,\"error\":\"Invalid (1-1000)\"}");
    }
  }

  // STATUS
  else if (cmd == "STATUS" || cmd == "?") {
    sendEncoderData();
  }

  // INFO
  else if (cmd == "INFO") {
    Serial.print("{\"model\":\"E40H8-1024-3-T-24\"");
    Serial.print(",\"ppr\":");
    Serial.print(ENCODER_PPR);
    Serial.print(",\"cpr\":");
    Serial.print(COUNTS_PER_REV);
    Serial.print(",\"hz\":");
    Serial.print(1000 / UPDATE_INTERVAL_MS);
    Serial.print(",\"baud\":");
    Serial.print(SERIAL_BAUD);
    Serial.print(",\"offset\":");
    Serial.print(enc_offset);
    Serial.print(",\"z_correction\":");
    Serial.print(use_z_correction ? "true" : "false");
    Serial.print(",\"tolerance_cnt\":");
    Serial.print(position_tolerance);
    Serial.println(",\"ok\":true}");
  }

  // 알 수 없는 명령
  else {
    Serial.print("{\"cmd\":\"UNKNOWN\",\"input\":\"");
    Serial.print(cmd);
    Serial.println("\",\"ok\":false}");
  }
}

// ============================================================
// setup
// ============================================================
void setup() {
  Serial.begin(SERIAL_BAUD);
  while (!Serial) { delay(10); }

  // 핀 설정 (토템폴 출력 → 외부 풀업 없이 INPUT 사용)
  pinMode(ENC_PIN_A, INPUT);
  pinMode(ENC_PIN_B, INPUT);
  pinMode(ENC_PIN_Z, INPUT);

  // NVS에서 저장값 복원
  loadOffset();
  loadAllPositions();

  // 초기 AB 상태 읽기
  enc_last_state = (digitalRead(ENC_PIN_B) << 1) | digitalRead(ENC_PIN_A);

  // 인터럽트 설정
  attachInterrupt(digitalPinToInterrupt(ENC_PIN_A), enc_ab_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC_PIN_B), enc_ab_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC_PIN_Z), enc_z_isr,  RISING);

  start_time     = millis();
  last_update_time = start_time;

  // 시작 메시지
  Serial.print("{\"msg\":\"E40H8-1024-3-T-24 Ready\"");
  Serial.print(",\"ppr\":");
  Serial.print(ENCODER_PPR);
  Serial.print(",\"cpr\":");
  Serial.print(COUNTS_PER_REV);
  Serial.print(",\"offset\":");
  Serial.print(enc_offset);
  Serial.println(",\"ok\":true}");
}

// ============================================================
// loop
// ============================================================
void loop() {
  unsigned long now = millis();

  // 주기적 데이터 전송
  if (now - last_update_time >= UPDATE_INTERVAL_MS) {
    last_update_time = now;
    sendEncoderData();
  }

  // 시리얼 명령 수신
  while (Serial.available() > 0) {
    char c = Serial.read();
    if (c == '\n' || c == '\r') {
      if (serial_buffer.length() > 0) {
        processCommand(serial_buffer);
        serial_buffer = "";
      }
    } else {
      serial_buffer += c;
      if (serial_buffer.length() > 64) {
        serial_buffer = "";
      }
    }
  }
}

