  else if (cmd == "ZUSE") {
    use_z_correction = true;
    comPrintln("{\"cmd\":\"ZUSE\",\"z_correction\":true,\"ok\":true}");
  }
  else if (cmd == "ZNUSE") {
    use_z_correction = false;
    comPrintln("{\"cmd\":\"ZNUSE\",\"z_correction\":false,\"ok\":true}");
  }

  // TOL n
  else if (cmd.startsWith("TOL ")) {
    int tol = cmd.substring(4).toInt();
    if (tol >= 1 && tol <= 1000) {
      position_tolerance = tol;
      float tol_deg = (float)tol / COUNTS_PER_REV * 360.0f;
      comPrint("{\"cmd\":\"TOL\",\"cnt\":");
      comPrint(tol);
      comPrint(",\"deg\":");
      comPrint(tol_deg, 3);
      comPrintln(",\"ok\":true}");
    } else {
      comPrintln("{\"cmd\":\"TOL\",\"ok\":false,\"error\":\"Invalid (1-1000)\"}");
    }
  }

  // STATUS
  else if (cmd == "STATUS" || cmd == "?") {
    sendEncoderData();
  }

  // INFO
  else if (cmd == "INFO") {
    comPrint("{\"model\":\"E40H8-1024-3-T-24\"");
    comPrint(",\"ppr\":");
    comPrint(ENCODER_PPR);
    comPrint(",\"cpr\":");
    comPrint(COUNTS_PER_REV);
    comPrint(",\"hz\":");
    comPrint(1000 / UPDATE_INTERVAL_MS);
    comPrint(",\"baud\":");
    comPrint(SERIAL_BAUD);
    comPrint(",\"offset\":");
    comPrint(enc_offset);
    comPrint(",\"z_correction\":");
    comPrint(use_z_correction ? "true" : "false");
    comPrint(",\"tolerance_cnt\":");
    comPrint(position_tolerance);
    comPrint(",\"uart_tx\":");
    comPrint(UART_TX_PIN);
    comPrint(",\"uart_rx\":");
    comPrint(UART_RX_PIN);
    comPrintln(",\"ok\":true}");
  }

  // 알 수 없는 명령
  else {
    comPrint("{\"cmd\":\"UNKNOWN\",\"input\":\"");
    comPrint(cmd);
    comPrintln("\",\"ok\":false}");
  }
}

// ============================================================
// 수신 버퍼 처리 (공통)
// ============================================================
void processBuf(char c, String& buf) {
  if (c == '\n' || c == '\r') {
    if (buf.length() > 0) {
      processCommand(buf);
      buf = "";
    }
  } else {
    buf += c;
    if (buf.length() > 64) buf = "";
  }
}

// ============================================================
// setup
// ============================================================
void setup() {
  // USB CDC 시리얼
  Serial.begin(SERIAL_BAUD);
  while (!Serial) { delay(10); }

  // GPIO UART 시리얼 (TX=16, RX=17)
  Serial1.begin(SERIAL_BAUD, SERIAL_8N1, UART_RX_PIN, UART_TX_PIN);

  // 핀 설정 (토템폴 출력 → 외부 풀업 없이 INPUT 사용)
  pinMode(ENC_PIN_A, INPUT);
  pinMode(ENC_PIN_B, INPUT);
  pinMode(ENC_PIN_Z, INPUT);

  // NVS에서 저장값 복원
  loadOffset();
  loadAllPositions();

  // 초기 AB 상태 읽기
  enc_last_state = (digitalRead(ENC_PIN_B) << 1) | digitalRead(ENC_PIN_A);

  // 인터럽트 설정
  attachInterrupt(digitalPinToInterrupt(ENC_PIN_A), enc_ab_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC_PIN_B), enc_ab_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC_PIN_Z), enc_z_isr,  RISING);

  start_time       = millis();
  last_update_time = start_time;

  // 시작 메시지
  comPrint("{\"msg\":\"E40H8-1024-3-T-24 Ready\"");
  comPrint(",\"ppr\":");
  comPrint(ENCODER_PPR);
  comPrint(",\"cpr\":");
  comPrint(COUNTS_PER_REV);
  comPrint(",\"offset\":");
  comPrint(enc_offset);
  comPrint(",\"uart_tx\":");
  comPrint(UART_TX_PIN);
  comPrint(",\"uart_rx\":");
  comPrint(UART_RX_PIN);
  comPrintln(",\"ok\":true}");
}

// ============================================================
// loop
// ============================================================
void loop() {
  unsigned long now = millis();

  // 주기적 데이터 전송
  if (now - last_update_time >= UPDATE_INTERVAL_MS) {
    last_update_time = now;
    sendEncoderData();
  }

  // USB CDC 수신
  while (Serial.available() > 0) {
    processBuf((char)Serial.read(), buf_usb);
  }

  // GPIO UART 수신
  while (Serial1.available() > 0) {
    processBuf((char)Serial1.read(), buf_uart);
  }
}

